10	export function getRouter(history: RouterHistory) {
11	  const queryClient = new QueryClient();
12	
13	  return createRouter({
14	    routeTree,
15	    history,
16	    context: {
17	      queryClient,
18	    },
19	    Wrap: ({ children }) =>
20	      createElement(
