/**
 * Named color theme definitions for T3 Code.
 *
 * Each theme defines a complete set of CSS custom property values covering
 * all major UI surfaces. The web app's ThemeProvider applies these as inline
 * styles on :root, taking precedence over the stylesheet defaults.
 */

/** The identifiers for the three built-in color themes. */
export type AppThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** A stored theme selection — may be a specific theme or "system". */
export type ThemeSelection = AppThemeId | "system";

/**
 * The complete set of CSS variable values for a theme.
 * Keys map directly to CSS custom property names (without the leading `--`).
 */
export interface ThemeColorTokens {
  // ── Core semantic colors ──────────────────────────────────────────────────
  background: string;
  foreground: string;
  card: string;
  "card-foreground": string;
  popover: string;
  "popover-foreground": string;
  primary: string;
  "primary-foreground": string;
  secondary: string;
  "secondary-foreground": string;
  muted: string;
  "muted-foreground": string;
  accent: string;
  "accent-foreground": string;
  border: string;
  input: string;
  ring: string;
  destructive: string;
  "destructive-foreground": string;
  info: string;
  "info-foreground": string;
  success: string;
  "success-foreground": string;
  warning: string;
  "warning-foreground": string;
  // ── Extended surface tokens ───────────────────────────────────────────────
  /** Main navigation / project sidebar background. */
  sidebar: string;
  "sidebar-foreground": string;
  "sidebar-border": string;
  /** Code / diff editor surface. */
  editor: string;
  "editor-foreground": string;
  /** Integrated terminal surface. */
  terminal: string;
  "terminal-foreground": string;
  /** Bottom status / info bar. */
  "status-bar": string;
  "status-bar-foreground": string;
}

/** A fully-described built-in color theme. */
export interface AppTheme {
  readonly id: AppThemeId;
  readonly name: string;
  readonly description: string;
  /** CSS `color-scheme` value — drives browser chrome (scrollbars, inputs, etc.). */
  readonly colorScheme: "light" | "dark";
  /**
   * Three representative CSS color values rendered as preview swatches:
   * [background, primary/accent, sidebar].
   */
  readonly swatches: readonly [string, string, string];
  readonly tokens: ThemeColorTokens;
}

// ─── Built-in themes ──────────────────────────────────────────────────────────

const T3_LIGHT: AppTheme = {
  id: "t3-light",
  name: "T3 Light",
  description: "Clean white workspace with crisp contrast.",
  colorScheme: "light",
  swatches: ["#ffffff", "#4f6ef7", "#f5f5f5"],
  tokens: {
    background: "#ffffff",
    foreground: "#262626",
    card: "#ffffff",
    "card-foreground": "#262626",
    popover: "#ffffff",
    "popover-foreground": "#262626",
    primary: "oklch(0.488 0.217 264)",
    "primary-foreground": "#ffffff",
    secondary: "rgba(0, 0, 0, 0.04)",
    "secondary-foreground": "#262626",
    muted: "rgba(0, 0, 0, 0.04)",
    "muted-foreground": "#6b6b6b",
    accent: "rgba(0, 0, 0, 0.04)",
    "accent-foreground": "#262626",
    border: "rgba(0, 0, 0, 0.08)",
    input: "rgba(0, 0, 0, 0.10)",
    ring: "oklch(0.488 0.217 264)",
    destructive: "#ef4444",
    "destructive-foreground": "#b91c1c",
    info: "#3b82f6",
    "info-foreground": "#1d4ed8",
    success: "#10b981",
    "success-foreground": "#065f46",
    warning: "#f59e0b",
    "warning-foreground": "#92400e",
    sidebar: "#f5f5f5",
    "sidebar-foreground": "#404040",
    "sidebar-border": "rgba(0, 0, 0, 0.08)",
    editor: "#ffffff",
    "editor-foreground": "#262626",
    terminal: "#fafafa",
    "terminal-foreground": "#262626",
    "status-bar": "#ebebeb",
    "status-bar-foreground": "#525252",
  },
};

const T3_DARK: AppTheme = {
  id: "t3-dark",
  name: "T3 Dark",
  description: "Deep neutral dark theme, easy on the eyes.",
  colorScheme: "dark",
  swatches: ["#0d0d0d", "#6680ff", "#0a0a0a"],
  tokens: {
    background: "#0d0d0d",
    foreground: "#f5f5f5",
    card: "#111111",
    "card-foreground": "#f5f5f5",
    popover: "#111111",
    "popover-foreground": "#f5f5f5",
    primary: "oklch(0.588 0.217 264)",
    "primary-foreground": "#ffffff",
    secondary: "rgba(255, 255, 255, 0.04)",
    "secondary-foreground": "#f5f5f5",
    muted: "rgba(255, 255, 255, 0.04)",
    "muted-foreground": "#8a8a8a",
    accent: "rgba(255, 255, 255, 0.04)",
    "accent-foreground": "#f5f5f5",
    border: "rgba(255, 255, 255, 0.06)",
    input: "rgba(255, 255, 255, 0.08)",
    ring: "oklch(0.588 0.217 264)",
    destructive: "#f87171",
    "destructive-foreground": "#fca5a5",
    info: "#60a5fa",
    "info-foreground": "#93c5fd",
    success: "#34d399",
    "success-foreground": "#6ee7b7",
    warning: "#fbbf24",
    "warning-foreground": "#fcd34d",
    sidebar: "#0a0a0a",
    "sidebar-foreground": "#d4d4d4",
    "sidebar-border": "rgba(255, 255, 255, 0.06)",
    editor: "#090909",
    "editor-foreground": "#f5f5f5",
    terminal: "#000000",
    "terminal-foreground": "#f0f0f0",
    "status-bar": "#141414",
    "status-bar-foreground": "#a3a3a3",
  },
};

const T3_MIDNIGHT: AppTheme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  description: "Rich blue-black with an indigo accent palette.",
  colorScheme: "dark",
  swatches: ["#080c14", "#7b9fff", "#050810"],
  tokens: {
    background: "#080c14",
    foreground: "#d0daf0",
    card: "#0c1220",
    "card-foreground": "#d0daf0",
    popover: "#0c1220",
    "popover-foreground": "#d0daf0",
    primary: "oklch(0.63 0.19 265)",
    "primary-foreground": "#ffffff",
    secondary: "rgba(90, 130, 255, 0.07)",
    "secondary-foreground": "#d0daf0",
    muted: "rgba(90, 130, 255, 0.07)",
    "muted-foreground": "#7a8aaa",
    accent: "rgba(90, 130, 255, 0.10)",
    "accent-foreground": "#d0daf0",
    border: "rgba(90, 130, 255, 0.14)",
    input: "rgba(90, 130, 255, 0.12)",
    ring: "oklch(0.63 0.19 265)",
    destructive: "#f87171",
    "destructive-foreground": "#fca5a5",
    info: "#60a5fa",
    "info-foreground": "#93c5fd",
    success: "#34d399",
    "success-foreground": "#6ee7b7",
    warning: "#fbbf24",
    "warning-foreground": "#fcd34d",
    sidebar: "#050810",
    "sidebar-foreground": "#b0bcd8",
    "sidebar-border": "rgba(90, 130, 255, 0.12)",
    editor: "#060a12",
    "editor-foreground": "#d0daf0",
    terminal: "#030508",
    "terminal-foreground": "#c8d4e8",
    "status-bar": "#0a1028",
    "status-bar-foreground": "#7a90c0",
  },
};

/** All built-in themes in display order. */
export const BUILT_IN_THEMES: ReadonlyArray<AppTheme> = [T3_LIGHT, T3_DARK, T3_MIDNIGHT];

/**
 * Look up a built-in theme by ID.
 * @throws if `id` is not a known built-in theme identifier.
 */
export function getThemeById(id: AppThemeId): AppTheme {
  const theme = BUILT_IN_THEMES.find((t) => t.id === id);
  if (!theme) throw new Error(`Unknown theme id: "${id}"`);
  return theme;
}

/**
 * The theme ID used when no preference has been stored and the system
 * preference resolves to dark.
 */
export const DEFAULT_DARK_THEME_ID: AppThemeId = "t3-dark";

/**
 * The theme ID used when no preference has been stored and the system
 * preference resolves to light.
 */
export const DEFAULT_LIGHT_THEME_ID: AppThemeId = "t3-light";

