import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useSyncExternalStore,
  type ReactNode,
} from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_DARK_THEME_ID,
  DEFAULT_LIGHT_THEME_ID,
  getThemeById,
  type AppTheme,
  type AppThemeId,
  type ThemeSelection,
} from "@t3tools/shared/theme";

// ─── Storage & DOM helpers ────────────────────────────────────────────────────

const STORAGE_KEY = "t3code:color-theme";
const SYSTEM_DARK_MEDIA = "(prefers-color-scheme: dark)";

function getStoredSelection(): ThemeSelection {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw === "system") return "system";
    if (BUILT_IN_THEMES.some((t) => t.id === raw)) return raw as AppThemeId;
  } catch {
    // localStorage may be unavailable (SSR / sandboxed iframe)
  }
  return "system";
}

function getSystemIsDark(): boolean {
  return window.matchMedia(SYSTEM_DARK_MEDIA).matches;
}

function resolveThemeId(selection: ThemeSelection): AppThemeId {
  if (selection !== "system") return selection;
  return getSystemIsDark() ? DEFAULT_DARK_THEME_ID : DEFAULT_LIGHT_THEME_ID;
}

/**
 * Imperatively apply a theme to the document root.
 *
 * Sets every CSS custom property defined in the theme's token map as an inline
 * style on `:root`, which takes precedence over the stylesheet defaults.
 * Also toggles the `.dark` class and `color-scheme` property that Tailwind and
 * the browser use to render native controls.
 */
function applyThemeToDOM(theme: AppTheme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  root.style.setProperty("color-scheme", theme.colorScheme);
  root.classList.toggle("dark", theme.colorScheme === "dark");

  for (const [key, value] of Object.entries(theme.tokens)) {
    root.style.setProperty(`--${key}`, value);
  }

  if (suppressTransitions) {
    // Force a synchronous reflow before removing the suppression class so
    // transitions do not animate the initial paint.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately at module import time to prevent a flash of the default
// CSS theme before React hydrates. This mirrors the existing useTheme pattern.
(function initTheme(): void {
  const selection = getStoredSelection();
  applyThemeToDOM(getThemeById(resolveThemeId(selection)));
})();

// ─── Module-level external store (mirrors useSyncExternalStore convention) ───

let storeListeners: Array<() => void> = [];

function emitChange(): void {
  for (const l of storeListeners) l();
}

type ThemeStoreSnapshot = { selection: ThemeSelection; systemDark: boolean };
let cachedSnapshot: ThemeStoreSnapshot | null = null;

function getStoreSnapshot(): ThemeStoreSnapshot {
  const selection = getStoredSelection();
  const systemDark = getSystemIsDark();
  if (
    cachedSnapshot &&
    cachedSnapshot.selection === selection &&
    cachedSnapshot.systemDark === systemDark
  ) {
    return cachedSnapshot;
  }
  cachedSnapshot = { selection, systemDark };
  return cachedSnapshot;
}

function subscribeToStore(listener: () => void): () => void {
  storeListeners.push(listener);

  const mq = window.matchMedia(SYSTEM_DARK_MEDIA);
  const handleMqChange = (): void => {
    if (getStoredSelection() === "system") {
      applyThemeToDOM(getThemeById(resolveThemeId("system")), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleMqChange);

  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      const selection = getStoredSelection();
      applyThemeToDOM(getThemeById(resolveThemeId(selection)), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    storeListeners = storeListeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMqChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ─── React context ────────────────────────────────────────────────────────────

export interface ThemeContextValue {
  /** The raw stored selection — may be "system". */
  colorTheme: ThemeSelection;
  /** The fully resolved AppTheme object (never "system"). */
  activeTheme: AppTheme;
  /**
   * The color scheme of the active theme: "light" | "dark".
   * Preserved for backwards-compatible destructuring in existing components.
   */
  resolvedTheme: "light" | "dark";
  /** All available built-in themes. */
  themes: ReadonlyArray<AppTheme>;
  setColorTheme: (id: ThemeSelection) => void;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: ReactNode }): React.JSX.Element {
  const snapshot = useSyncExternalStore(subscribeToStore, getStoreSnapshot);

  const resolvedThemeId = resolveThemeId(snapshot.selection);
  const activeTheme = getThemeById(resolvedThemeId);

  const setColorTheme = useCallback((id: ThemeSelection): void => {
    try {
      localStorage.setItem(STORAGE_KEY, id);
    } catch {
      // localStorage unavailable — apply in-memory only
    }
    applyThemeToDOM(getThemeById(resolveThemeId(id)), true);
    emitChange();
  }, []);

  // Keep the DOM in sync whenever the resolved theme changes (e.g. system
  // preference flip or storage event from another tab).
  useEffect(() => {
    applyThemeToDOM(activeTheme);
  }, [activeTheme]);

  const value: ThemeContextValue = {
    colorTheme: snapshot.selection,
    activeTheme,
    resolvedTheme: activeTheme.colorScheme,
    themes: BUILT_IN_THEMES,
    setColorTheme,
  };

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a ThemeProvider");
  }
  return ctx;
}

