import type { AppTheme, ThemeSelection } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

// ─── Mini theme preview ───────────────────────────────────────────────────────

/**
 * Renders a small mockup of the theme's color palette: a narrow sidebar strip
 * on the left, and a content area on the right with simulated text lines and
 * an accent dot row.
 */
function ThemePreview({ theme }: { theme: AppTheme }): React.JSX.Element {
  const { tokens } = theme;
  return (
    <div
      className="flex h-14 w-full overflow-hidden rounded-lg"
      style={{
        background: tokens.background,
        border: `1px solid ${tokens.border}`,
      }}
      aria-hidden="true"
    >
      {/* Sidebar strip */}
      <div
        className="flex w-9 shrink-0 flex-col items-center gap-1.5 px-1.5 py-2"
        style={{ background: tokens.sidebar }}
      >
        {([20, 28, 16] as const).map((w) => (
          <div
            key={w}
            className="rounded-sm"
            style={{
              height: "5px",
              width: `${w}px`,
              background: tokens["sidebar-foreground"],
              opacity: 0.35,
            }}
          />
        ))}
      </div>

      {/* Editor / content area */}
      <div className="flex flex-1 flex-col justify-center gap-1.5 px-3 py-2">
        {/* Simulated text lines */}
        <div className="flex gap-1.5">
          <div
            className="rounded-sm"
            style={{ height: "4px", width: "56px", background: tokens.foreground, opacity: 0.5 }}
          />
          <div
            className="rounded-sm"
            style={{ height: "4px", width: "32px", background: tokens.foreground, opacity: 0.25 }}
          />
        </div>
        <div
          className="rounded-sm"
          style={{ height: "4px", width: "72px", background: tokens.foreground, opacity: 0.3 }}
        />
        {/* Accent dots */}
        <div className="mt-0.5 flex gap-1">
          {(["dot-a", "dot-b", "dot-c"] as const).map((dotId) => (
            <div
              key={dotId}
              className="rounded-full"
              style={{ height: "5px", width: "5px", background: tokens.primary, opacity: 0.8 }}
            />
          ))}
        </div>
      </div>

      {/* Status bar hint */}
      <div
        className="flex w-8 shrink-0 items-end justify-center pb-1"
        style={{ background: tokens.background }}
      >
        <div
          className="rounded-sm"
          style={{ height: "3px", width: "20px", background: tokens["status-bar"] }}
        />
      </div>
    </div>
  );
}

// ─── Theme card ───────────────────────────────────────────────────────────────

interface ThemeCardProps {
  theme: AppTheme;
  selected: boolean;
  onSelect: (id: ThemeSelection) => void;
}

function ThemeCard({ theme, selected, onSelect }: ThemeCardProps): React.JSX.Element {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={() => onSelect(theme.id)}
      className={[
        "group relative flex flex-col gap-2.5 rounded-xl border p-3 text-left transition-colors",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        selected
          ? "border-primary/60 bg-primary/5"
          : "border-border bg-card hover:border-primary/30 hover:bg-accent/40",
      ].join(" ")}
    >
      {/* Mini theme preview */}
      <ThemePreview theme={theme} />

      {/* Theme info + selection badge */}
      <div className="flex items-start justify-between gap-2">
        <div className="min-w-0">
          <p className="text-sm font-medium text-foreground">{theme.name}</p>
          <p className="mt-0.5 text-xs text-muted-foreground">{theme.description}</p>
        </div>
        {selected && (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        )}
      </div>

      {/* Color swatch strip */}
      <div className="flex gap-1" aria-label="Color swatches">
        {(["Background", "Accent", "Sidebar"] as const).map((label, i) => (
          <div
            key={label}
            className="h-3 w-3 rounded-full ring-1 ring-border/40"
            style={{ backgroundColor: theme.swatches[i] }}
            title={label}
          />
        ))}
      </div>
    </button>
  );
}

// ─── ThemeSelector ────────────────────────────────────────────────────────────

/**
 * Displays all built-in themes as selectable cards with mini color previews and
 * swatch dots. Persists the selected theme via the ThemeProvider.
 *
 * Must be rendered inside a `<ThemeProvider>`.
 */
export function ThemeSelector(): React.JSX.Element {
  const { colorTheme, themes, setColorTheme, activeTheme } = useTheme();

  return (
    <div className="space-y-3">
      <div
        className="grid grid-cols-1 gap-3 sm:grid-cols-3"
        role="radiogroup"
        aria-label="Color theme"
      >
        {themes.map((theme) => (
          <ThemeCard
            key={theme.id}
            theme={theme}
            selected={colorTheme === theme.id}
            onSelect={setColorTheme}
          />
        ))}
      </div>

      <p className="text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{activeTheme.name}</span>
        {" · "}
        <span className="capitalize">{activeTheme.colorScheme}</span>
      </p>
    </div>
  );
}

