import React from "react";
import ReactDOM from "react-dom/client";
import { RouterProvider } from "@tanstack/react-router";
import { createHashHistory, createBrowserHistory } from "@tanstack/react-router";

import "@xterm/xterm/css/xterm.css";
import "./index.css";

import { isElectron } from "./env";
import { getRouter } from "./router";
import { APP_DISPLAY_NAME } from "./branding";
import { ThemeProvider } from "./contexts/ThemeContext";

const history = isElectron ? createHashHistory() : createBrowserHistory();

const router = getRouter(history);

document.title = APP_DISPLAY_NAME;

ReactDOM.createRoot(document.getElementById("root") as HTMLElement).render(
  <React.StrictMode>
    <ThemeProvider>
      <RouterProvider router={router} />
    </ThemeProvider>
  </React.StrictMode>,
);

/**
 * Re-exports the useTheme hook from ThemeContext so that existing import paths
 * (`../hooks/useTheme`) continue to work without modification.
 *
 * The hook now returns an extended value — see ThemeContext for the full API.
 * Existing destructuring of `{ resolvedTheme }` is fully backwards-compatible;
 * `resolvedTheme` is still typed as `"light" | "dark"`.
 */
export { useTheme } from "../contexts/ThemeContext";
export type { ThemeContextValue } from "../contexts/ThemeContext";
